INSERT INTO `products` VALUES (1,'Wood Crafts','descroipyio sample in',NULL,'data:image/webp;base64,','ABC',1000,10,8),(2,'Handicrafts','artyujhgfedsgfhmh',NULL,'data:image/webp;base64,','XYZ',10000,50,8),(5,'Handicrafts','123456',NULL,'data:image/jpeg;base64,','Tribe 1 prodiuct ',500,12,13),(6,'Wood Crafts','Beautiful hand-carved wooden bowl made from sustainable teak wood. Perfect for serving fruits or as decorative piece. Each piece is unique with natural wood grain patterns.',_binary '','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800','Handcrafted Wooden Bowl',1299,25,3),(7,'Wood Crafts','Traditional tribal mask hand-carved by skilled artisans. Features intricate designs representing ancient tribal symbols. Made from premium hardwood with natural finish.',_binary '','https://images.unsplash.com/photo-1582747652673-603191169c49?w=800','Tribal Wooden Mask',2499,15,3),(8,'Wood Crafts','Elegant wooden jewelry box with hand-carved floral patterns. Features multiple compartments and velvet lining. Perfect gift for loved ones.',_binary '\0','https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800','Wooden Jewelry Box',1899,30,3),(9,'Wood Crafts','Intricately carved wooden elephant statue. Symbol of wisdom and strength in tribal culture. Hand-painted with natural colors.',_binary '\0','https://images.unsplash.com/photo-1557180295-76eee20ae8aa?w=800','Decorative Wooden Elephant',1599,20,3),(12,'Handicrafts','Authentic handmade dream catcher with feathers and beads. Based on traditional tribal designs. Brings positive energy and peaceful sleep.',_binary '\0','https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800','Tribal Dream Catcher',699,50,3),(13,'Handicrafts','Beautiful macrame wall hanging with tribal patterns. Made from natural cotton threads. Adds bohemian touch to your home decor.',_binary '','https://images.unsplash.com/photo-1578749556568-bc2c40e68b61?w=800','Handwoven Wall Hanging',1299,35,3),(14,'Handicrafts','Melodious wind chimes made from bamboo and shells. Hand-painted with traditional designs. Creates soothing sounds in the breeze.',_binary '\0','https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800','Tribal Wind Chimes',799,45,3),(15,'Handicrafts','Unique table lamp with tribal-inspired shade. Hand-painted with natural dyes. Creates warm ambient lighting.',_binary '','https://images.unsplash.com/photo-1513506003901-1e6a229e2d15?w=800','Decorative Tribal Lamp',1999,20,3),(16,'Textiles','Traditional handloom cotton saree with tribal border designs. Soft, breathable fabric perfect for daily wear. Natural dyes used for coloring.',_binary '','https://images.unsplash.com/photo-1610030469983-98e550d6193c?w=800','Handloom Cotton Saree',2499,25,3),(17,'Textiles','Set of 4 cushion covers with authentic tribal prints. Made from premium cotton fabric. Adds ethnic touch to your living space.',_binary '\0','https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=800','Tribal Print Cushion Covers',899,60,3),(18,'Textiles','Beautiful handwoven table runner with geometric tribal patterns. Made from natural cotton and jute blend. Perfect for dining table decoration.',_binary '\0','https://images.unsplash.com/photo-1616486338812-3dadae4b4ace?w=800','Handwoven Table Runner',699,40,3),(19,'Textiles','Elegant stole with hand-embroidered tribal motifs. Soft wool blend fabric. Perfect accessory for traditional and modern outfits.',_binary '','https://images.unsplash.com/photo-1591047139829-d91aecb6caea?w=800','Tribal Embroidered Stole',1599,30,3),(20,'Textiles','Premium handloom bedsheet set with tribal border designs. Includes 1 bedsheet and 2 pillow covers. 100% cotton, soft and durable.',_binary '','https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=800','Handloom Bedsheet Set',2999,20,3),(21,'Pottery','Set of 3 handmade terracotta planters with tribal designs. Perfect for indoor plants. Natural clay with hand-painted patterns.',_binary '\0','https://images.unsplash.com/photo-1578500494198-246f612d3b3d?w=800','Terracotta Planter Set',799,35,3),(22,'Pottery','Traditional clay water pot (matka) that keeps water naturally cool. Hand-crafted using ancient pottery techniques. Eco-friendly and healthy.',_binary '','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800','Clay Water Pot',599,50,3),(23,'Pottery','Beautiful ceramic vase with hand-painted tribal motifs. Perfect for flowers or as standalone decorative piece. Glazed finish.',_binary '','https://images.unsplash.com/photo-1578749556568-bc2c40e68b61?w=800','Decorative Ceramic Vase',1299,25,3),(26,'Jewelry','Authentic tribal silver necklace with traditional pendant. Handcrafted by skilled artisans. Features intricate filigree work.',_binary '','https://images.unsplash.com/photo-1599643478518-a784e5dc4c8f?w=800','Tribal Silver Necklace',3499,15,3),(27,'Jewelry','Colorful beaded bracelet with traditional tribal patterns. Made from natural beads and threads. Adjustable size.',_binary '\0','https://images.unsplash.com/photo-1611591437281-460bfbe1220a?w=800','Beaded Tribal Bracelet',499,80,3),(28,'Jewelry','Traditional oxidized silver jhumka earrings with tribal designs. Lightweight and comfortable. Perfect for ethnic wear.',_binary '','https://images.unsplash.com/photo-1535632066927-ab7c9ab60908?w=800','Oxidized Jhumka Earrings',899,50,3),(29,'Jewelry','Beautiful pair of tribal anklets with bells. Made from German silver with antique finish. Creates melodious sound while walking.',_binary '\0','https://images.unsplash.com/photo-1611591437281-460bfbe1220a?w=800','Tribal Anklet Pair',1299,30,3),(30,'Jewelry','Delicate tribal nose ring with traditional design. Made from pure silver. Comfortable and elegant.',_binary '\0','https://images.unsplash.com/photo-1599643478518-a784e5dc4c8f?w=800','Handcrafted Nose Ring',699,40,3),(31,'Home Decor','Decorative wall mirror with hand-carved wooden frame featuring tribal motifs. Adds ethnic elegance to any room.',_binary '','https://images.unsplash.com/photo-1618220179428-22790b461013?w=800','Tribal Wall Mirror',2299,20,3),(32,'Home Decor','Handcrafted brass statue depicting tribal deity. Traditional design with antique finish. Perfect for home temple or decoration.',_binary '\0','https://images.unsplash.com/photo-1582747652673-603191169c49?w=800','Brass Tribal Statue',1899,22,3),(33,'Home Decor','Colorful door hanging (toran) with beads and mirrors. Traditional tribal design. Brings positive energy to your home entrance.',_binary '\0','https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800','Tribal Door Hanging',599,60,3),(34,'Home Decor','Set of 3 wooden photo frames with hand-carved tribal patterns. Natural wood finish. Perfect for displaying family memories.',_binary '','https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800','Wooden Photo Frame Set',1499,35,3),(35,'Home Decor','Beautiful brass incense holder with tribal engravings. Comes with wooden base. Perfect for meditation and prayer.',_binary '\0','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800','Tribal Incense Holder',799,45,3),(36,'Wood Crafts','Set of 5 handcrafted wooden cooking spoons made from mango wood. Each spoon features unique grain patterns. Perfect for non-stick cookware. Food-safe natural finish.',_binary '','data:image/webp;base64,','Carved Wooden Spoon Set',899,38,8),(37,'Wood Crafts','Large rectangular serving tray with handles. Made from sustainable acacia wood. Perfect for breakfast in bed or entertaining guests. Natural wood grain finish.',_binary '','data:image/webp;base64,','Wooden Serving Tray',1799,25,8),(38,'Wood Crafts','Traditional wooden comb hand-carved from neem wood. Anti-static and gentle on hair. Promotes healthy scalp. Eco-friendly alternative to plastic combs.',_binary '\0','data:image/webp;base64,','Hand-Carved Wooden Comb',399,60,8),(39,'Wood Crafts','Set of 6 round wooden coasters with cork backing. Protects furniture from water rings. Natural wood finish with smooth edges. Comes in decorative holder.',_binary '\0','data:image/webp;base64,','Wooden Coaster Set',599,50,8),(42,'Handicrafts','Beautiful handmade paper diary with 200 pages. Eco-friendly recycled paper. Perfect for journaling, sketching, or note-taking. Comes with fabric bookmark.',_binary '','data:image/webp;base64,','Handmade Paper Diary',499,45,8),(44,'Handicrafts','Unique bowl made from natural coconut shell. Polished smooth finish. Perfect for serving snacks or as decorative piece. Eco-friendly and sustainable.',_binary '\0','data:image/webp;base64,','Coconut Shell Bowl',349,70,8),(45,'Handicrafts','Natural jute area rug (3x5 feet). Handwoven with traditional techniques. Durable and eco-friendly. Perfect for living room or bedroom. Easy to clean.',_binary '','data:image/webp;base64,','Handwoven Jute Rug',2499,20,8),(46,'Textiles','Beautiful hand block printed cotton dupatta. Traditional Rajasthani designs. Soft and breathable fabric. Perfect for ethnic wear. Natural vegetable dyes used.',_binary '','data:image/webp;base64,','Block Print Cotton Dupatta',899,38,8),(47,'Textiles','Set of 3 handloom cotton towels (bath, hand, face). Highly absorbent and quick-drying. Soft on skin. Traditional weaving techniques. Long-lasting quality.',_binary '\0','data:image/webp;base64,','Handloom Cotton Towel Set',1299,35,8),(48,'Textiles','Vibrant tie-dye cotton scarf with traditional patterns. Lightweight and versatile. Can be worn as scarf, headband, or belt. Hand-dyed with natural colors.',_binary '\0','data:image/webp;base64,','Tie-Dye Cotton Scarf',599,54,8);
INSERT INTO `products` VALUES (49,'Textiles','Cozy cotton throw blanket with tribal stripes. Perfect for couch or bed. Handwoven on traditional looms. Soft, warm, and durable. Machine washable.',_binary '','data:image/webp;base64,','Handwoven Cotton Throw',1899,25,8),(50,'Textiles','Set of 4 cotton placemats with hand embroidery. Protects table from spills and stains. Easy to wash. Adds elegance to dining table. Traditional motifs.',_binary '\0','data:image/webp;base64,','Embroidered Cotton Placemats',799,45,8),(51,'Pottery','Set of 6 traditional clay cups (kulhad) for tea/coffee. Enhances beverage flavor. Eco-friendly and biodegradable. Authentic chai experience. Single-use or reusable.',_binary '','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800&q=80','Handmade Clay Kulhad Set',199,120,8),(52,'Pottery','Traditional clay cooking pot (handi) with lid. Retains heat well. Perfect for slow cooking curries and rice. Healthy cooking option. Seasoned and ready to use.',_binary '','https://images.unsplash.com/photo-1578500494198-246f612d3b3d?w=800&q=80','Terracotta Cooking Pot',899,30,8),(53,'Pottery','Handcrafted ceramic tea set with teapot and 4 cups. Hand-painted floral designs. Microwave safe. Perfect for tea parties. Comes in gift box.',_binary '','https://images.unsplash.com/photo-1578749556568-bc2c40e68b61?w=800&q=80','Ceramic Tea Set',1799,20,8),(54,'Pottery','Cute handmade clay piggy bank for kids. Hand-painted with bright colors. Teaches saving habits. Makes great gift. Break to open design.',_binary '\0','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800&q=80','Clay Piggy Bank',299,80,8),(55,'Pottery','Beautiful terracotta hanging planter with jute rope. Perfect for succulents and small plants. Drainage hole included. Adds rustic charm to balcony or patio.',_binary '\0','https://images.unsplash.com/photo-1578500494198-246f612d3b3d?w=800&q=80','Terracotta Hanging Planter',499,50,8),(56,'Jewelry','Lightweight terracotta earrings with hand-painted designs. Hypoallergenic. Perfect for daily wear. Unique tribal patterns. Comfortable for all-day wear.',_binary '','https://images.unsplash.com/photo-1535632066927-ab7c9ab60908?w=800&q=80','Terracotta Earrings',399,60,8),(57,'Jewelry','Long wooden bead necklace with natural finish. Lightweight and comfortable. Bohemian style. Perfect for casual and ethnic wear. Adjustable length.',_binary '\0','https://images.unsplash.com/photo-1599643478518-a784e5dc4c8f?w=800&q=80','Wooden Bead Necklace',699,45,8),(58,'Jewelry','Traditional brass kada (bangle) with engraved patterns. Adjustable size. Antique finish. Suitable for men and women. Durable and long-lasting.',_binary '\0','https://images.unsplash.com/photo-1611591437281-460bfbe1220a?w=800&q=80','Brass Kada Bracelet',599,46,8),(59,'Jewelry','Natural cowrie shell pendant on cotton thread. Adjustable length. Beach-inspired design. Lightweight and comfortable. Perfect summer accessory.',_binary '','https://images.unsplash.com/photo-1599643478518-a784e5dc4c8f?w=800&q=80','Shell Pendant Necklace',449,55,8),(60,'Jewelry','Set of 3 colorful seed bead bracelets. Elastic fit. Stackable design. Handmade with love. Perfect for gifting. Vibrant tribal colors.',_binary '\0','https://images.unsplash.com/photo-1611591437281-460bfbe1220a?w=800&q=80','Seed Bead Bracelet Set',349,70,8),(61,'Home Decor','Handcrafted bamboo wind chime with 7 tubes. Creates soothing sounds. Perfect for garden, balcony, or patio. Natural bamboo with weather-resistant coating.',_binary '','data:image/webp;base64,','Bamboo Wind Chime',799,38,8),(62,'Home Decor','Set of 6 round jute table mats. Heat-resistant and durable. Protects table surface. Natural eco-friendly material. Easy to clean with damp cloth.',_binary '\0','https://images.unsplash.com/photo-1616486338812-3dadae4b4ace?w=800&q=80','Jute Table Mat Set',599,50,8),(63,'Home Decor','Wall-mounted wooden key holder with 5 hooks. Hand-carved design. Keeps keys organized. Easy to install. Perfect for entryway. Includes mounting hardware.',_binary '\0','https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800&q=80','Wooden Key Holder',499,45,8),(64,'Home Decor','Decorative terracotta wall art with tribal motifs. Hand-painted with natural colors. Adds ethnic touch to walls. Lightweight and easy to hang.',_binary '','https://images.unsplash.com/photo-1578500494198-246f612d3b3d?w=800&q=80','Terracotta Wall Hanging',899,30,8),(66,'Kitchen & Dining','Traditional wooden mortar and pestle for grinding spices. Made from hardwood. Durable and long-lasting. Perfect for fresh spice blends. Easy to clean.',_binary '','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800&q=80','Wooden Mortar & Pestle',699,35,8),(67,'Kitchen & Dining','Eco-friendly bamboo cutlery set with fork, spoon, knife, and chopsticks. Reusable and biodegradable. Perfect for travel or office. Comes with carrying pouch.',_binary '\0','data:image/avif;base64,','Bamboo Cutlery Set',399,79,8),(68,'Kitchen & Dining','Natural clay water bottle (surahi) that keeps water cool. Traditional design with narrow neck. Eco-friendly alternative to plastic. Healthy drinking option.',_binary '','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800&q=80','Clay Water Bottle',799,40,8),(69,'Kitchen & Dining','Large wooden salad bowl with smooth finish. Perfect for serving salads, fruits, or snacks. Made from sustainable wood. Food-safe natural oil finish.',_binary '\0','https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800&q=80','Wooden Salad Bowl',1299,25,8),(73,'Electronics','A test product for delivery testing',NULL,NULL,'Test Product',100,10,15);
